// EXTRACT RFQ REFERENCE ID
try {
  const item = $input.first().json;
  const subject = item.subject || '';
  const from = item.from?.text || item.from || '';
  const refMatch = subject.match(/Ref:\s*\[?([A-Za-z0-9-]+)\]?/i);
  const refId = refMatch ? refMatch[1] : null;
  if (!refId) { console.log('No Ref ID found in subject: ' + subject); return []; }
  const nameMatch = from.match(/^([^<]+)/);
  const agentName = nameMatch ? nameMatch[1].trim().replace(/\"/g, '') : 'Unknown Agent';
  const agentEmail = item.from?.value?.[0]?.address || (typeof item.from === 'string' ? item.from : 'unknown@agent.com');
  return [{ json: { refId, subject, agentName, agentEmail, emailBody: item.text || item.snippet || '', receivedAt: item.date || new Date().toISOString() } }];
} catch (e) {
  console.log('Extract Ref ID failed: ' + e.message); return [];
}

