// ========================================
// MULTI-SHIPMENT + MULTI-CARRIER QUOTE PARSER
// Outputs ONE item per carrier option for Google Sheets
// Each row = one agent + one carrier + one shipment
// ========================================

try {
  const rawInput = $input.first();
  const extractRefData = $('Extract Ref ID').first()?.json || {};

  if (!rawInput || !rawInput.json) {
    return [{ json: { ...extractRefData, error: 'No AI input', isValidQuote: false } }];
  }

  const raw = rawInput.json.text || rawInput.json.output || '';
  let cleanData = {};

  if (!raw || raw.trim() === '') {
    cleanData = { error: 'Empty AI response', quotes: [] };
  } else {
    try {
      let cleanString = raw.replace(/```json/g, '').replace(/```/g, '').trim();
      const jsonMatch = cleanString.match(/\{[\s\S]*\}/);
      if (jsonMatch) cleanString = jsonMatch[0];
      cleanData = JSON.parse(cleanString);
    } catch (parseErr) {
      cleanData = { error: 'JSON parse failed: ' + parseErr.message, quotes: [] };
    }
  }

  function normalizeCarrier(carrier) {
    if (!carrier || typeof carrier !== 'string') return null;
    let c = carrier.trim().toUpperCase();
    if (c.includes('COSCO')) return 'COSCO';
    if (c.includes('EVERGREEN')) return 'EVERGREEN';
    if (c.includes('MEDITERRANEAN') || c === 'MSC') return 'MSC';
    if (c.includes('ONE') && c.length <= 10) return 'ONE';
    if (c.includes('MAERSK')) return 'MAERSK';
    if (c.includes('HAPAG') || c.includes('LLOYD')) return 'HAPAG-LLOYD';
    if (c.includes('CMA') || c.includes('CGM')) return 'CMA CGM';
    if (c.includes('YANG MING') || c === 'YML') return 'YANG MING';
    if (c.includes('HMM') || c.includes('HYUNDAI')) return 'HMM';
    if (c.includes('ZIM')) return 'ZIM';
    return c;
  }

  const quotes = cleanData.quotes || [];

  if (!Array.isArray(quotes) || quotes.length === 0) {
    return [{ json: {
      ...extractRefData,
      error: 'No quotes in response',
      carrier: null, price: null, currency: null,
      validity: null, transit_time: null, free_time: null, etd: null,
      shipment_number: null, isValidQuote: false
    }}];
  }

  // Output ONE item per quote (per carrier option per shipment)
  return quotes.map(quote => {
    const price = quote.price;
    const isValidQuote = price !== null &&
      price !== undefined &&
      price !== 'NO_QUOTE' &&
      !isNaN(parseFloat(price)) &&
      parseFloat(price) > 0;

    return {
      json: {
        ...extractRefData,
        shipment_number: quote.shipment_number || 1,
        carrier: normalizeCarrier(quote.carrier) || 'N/A',
        price: isValidQuote ? price : 'N/A',
        currency: quote.currency || 'USD',
        validity: quote.validity || 'N/A',
        transit_time: quote.transit_time ?? 'N/A',
        free_time: quote.free_time ?? 'N/A',
        etd: quote.etd || 'N/A',
        isValidQuote,
        quote_count: quotes.length
      }
    };
  });

} catch (e) {
  return [{ json: {
    error: 'Parse failed: ' + e.message,
    carrier: null, price: null, currency: null,
    validity: null, transit_time: null, free_time: null, etd: null,
    isValidQuote: false
  }}];
}

// ========================================
// COUNT & CHECK QUOTES - SHIPMENT-BASED FORMAT
// Access data from both Get All Quotes AND Get Master Status
// ========================================

try {
  const allQuotes = $input.all();
  const masterRfq = $('Get Master Status').first().json;

  // Handle empty input
  if (!allQuotes || allQuotes.length === 0) {
    return [{
      json: {
        quoteCount: 0,
        thresholdMet: false,
        bestPrice: null,
        bestAgent: '',
        bestCarrier: '',
        rfqRef: null,
        summaryText: 'No quotes received',
        summaryHtml: '<p>No quotes received</p>',
        totalResponses: 0,
        error: 'No input items'
      }
    }];
  }

  // ========================================
  // GET SHIPMENT DETAILS FROM MASTER RFQ
  // ========================================

  const rfqRef = masterRfq.rfq_id || null;

  const serviceType = (masterRfq.service_type || 'port-to-port').toLowerCase().trim();
  const hasDoorService = serviceType !== 'port-to-port';
  const hasPickup = serviceType === 'door-to-port' || serviceType === 'door-to-door';
  const hasDelivery = serviceType === 'port-to-door' || serviceType === 'door-to-door';

  const shipmentDetails = {
    pol: masterRfq.pol || 'N/A',
    pod: masterRfq.pod || 'N/A',
    containerType: masterRfq.container_type || 'N/A',
    qty: masterRfq.qty || 'N/A',
    readyDate: masterRfq.ready_date || 'N/A',
    serviceType,
    pickupAddress: masterRfq.pickup_address || null,
    deliveryAddress: masterRfq.delivery_address || null
  };

  // ========================================
  // FILTER VALID QUOTES
  // ========================================

  const validQuotes = allQuotes.filter(item => {
    const price = item.json.price || item.json.ocean_freight;

    if (typeof price === 'string' && price.includes('\n')) {
      const prices = price.split('\n');
      return prices.some(p => {
        const trimmed = p.trim();
        return trimmed !== 'NO_QUOTE' &&
               trimmed !== '' &&
               trimmed !== 'N/A' &&
               !isNaN(parseFloat(trimmed)) &&
               parseFloat(trimmed) > 0;
      });
    }

    return price &&
           price !== 'NO_QUOTE' &&
           price !== '' &&
           price !== 'N/A' &&
           !isNaN(parseFloat(price)) &&
           parseFloat(price) > 0;
  });

  // ========================================
  // HELPER FUNCTIONS
  // ========================================

  function parseMultiValue(value) {
    if (!value) return ['N/A'];
    if (typeof value === 'string' && value.includes('\n')) {
      return value.split('\n').map(v => v.trim());
    }
    return [value];
  }

  // ========================================
  // PARSE MULTI-SHIPMENT DATA
  // ========================================

  const pols = parseMultiValue(shipmentDetails.pol);
  const pods = parseMultiValue(shipmentDetails.pod);
  const containerTypes = parseMultiValue(shipmentDetails.containerType);
  const qtys = parseMultiValue(shipmentDetails.qty);
  const readyDates = parseMultiValue(shipmentDetails.readyDate);

  const shipmentCount = Math.max(pols.length, pods.length, containerTypes.length);

  // ========================================
  // BUILD SHIPMENT-BASED QUOTE STRUCTURE
  // ========================================

  const shipmentQuotes = [];

  for (let i = 0; i < shipmentCount; i++) {
    const shipmentNum = i + 1;
    const shipment = {
      number: shipmentNum,
      pol: pols[i] || 'N/A',
      pod: pods[i] || 'N/A',
      containerType: containerTypes[i] || 'N/A',
      qty: qtys[i] || 'N/A',
      readyDate: readyDates[i] || 'N/A',
      serviceType: shipmentDetails.serviceType,
      pickupAddress: shipmentDetails.pickupAddress,
      deliveryAddress: shipmentDetails.deliveryAddress,
      quotes: []
    };

    for (const q of validQuotes) {
      const agent = q.json.agent_name || 'Unknown';
      const rawPrice = q.json.price || q.json.ocean_freight;
      const rawCarrier = q.json.carrier || 'TBD';
      const rawValidity = q.json.validity || 'N/A';
      const rawTransit = q.json.transit_time || 'N/A';
      const rawEtd = q.json.etd || 'N/A';
      const rawFreeTime = q.json.free_time || 'N/A';

      const prices = parseMultiValue(rawPrice);
      const carriers = parseMultiValue(rawCarrier);
      const validities = parseMultiValue(rawValidity);
      const transits = parseMultiValue(rawTransit);
      const etds = parseMultiValue(rawEtd);
      const freeTimes = parseMultiValue(rawFreeTime);

      const price = prices[i];
      const carrier = carriers[i] || carriers[0];
      const validity = validities[i] || validities[0];
      const transit = transits[i] || transits[0];
      const etd = etds[i] || etds[0];
      const freeTime = freeTimes[i] || freeTimes[0];

      if (price && price !== 'N/A' && !isNaN(parseFloat(price))) {
        shipment.quotes.push({
          agent,
          carrier,
          price: parseFloat(price),
          etd,
          transit,
          freeTime,
          validity
        });
      }
    }

    shipment.quotes.sort((a, b) => a.price - b.price);
    shipmentQuotes.push(shipment);
  }

  // ========================================
  // BUILD PLAIN TEXT SUMMARY
  // ========================================

  let textSummary = [];

  for (const shipment of shipmentQuotes) {
    textSummary.push(`\n━━━ SHIPMENT ${shipment.number} ━━━`);
    textSummary.push(`Route: ${shipment.pol} → ${shipment.pod}`);
    textSummary.push(`Container: ${shipment.qty} x ${shipment.containerType}`);
    textSummary.push(`Ready Date: ${shipment.readyDate}`);
    textSummary.push(`Service: ${shipment.serviceType.toUpperCase()}`);
    if (shipment.pickupAddress) textSummary.push(`Pickup: ${shipment.pickupAddress}`);
    if (shipment.deliveryAddress) textSummary.push(`Delivery: ${shipment.deliveryAddress}`);
    textSummary.push('');

    if (shipment.quotes.length === 0) {
      textSummary.push('  No quotes received');
    } else {
      for (let i = 0; i < shipment.quotes.length; i++) {
        const q = shipment.quotes[i];
        const rank = i === 0 ? '🏆' : `${i + 1}.`;
        textSummary.push(`  ${rank} ${q.agent}: USD $${q.price}`);
        textSummary.push(`     Carrier: ${q.carrier} | Transit: ${q.transit} days | ETD: ${q.etd}`);
        textSummary.push(`     Free Time: ${q.freeTime} days | Valid: ${q.validity}`);
      }
    }
  }

  // ========================================
  // BUILD HTML TABLE SUMMARY
  // ========================================

  let htmlSummary = '';

  for (const shipment of shipmentQuotes) {
    const serviceLabel = shipment.serviceType !== 'port-to-port'
      ? `<span style="background: #e3f2fd; color: #1565c0; padding: 2px 8px; border-radius: 12px; font-size: 11px; font-weight: bold; margin-left: 8px;">🚪 ${shipment.serviceType.toUpperCase()}</span>`
      : '';

    const addressBlock = (() => {
      const lines = [];
      if (shipment.pickupAddress) lines.push(`<div style="font-size:12px; color:#555; margin-top:3px;">📦 Pickup: ${shipment.pickupAddress}</div>`);
      if (shipment.deliveryAddress) lines.push(`<div style="font-size:12px; color:#555; margin-top:3px;">🏭 Delivery: ${shipment.deliveryAddress}</div>`);
      return lines.join('');
    })();

    htmlSummary += `
<div style="margin-bottom: 30px; border: 1px solid #e0e0e0; border-radius: 8px; overflow: hidden;">
  <div style="background: #f5f5f5; padding: 12px 15px; border-bottom: 2px solid #667eea;">
    <div style="display:flex; align-items:center;">
      <strong style="color: #333;">SHIPMENT ${shipment.number}</strong>
      ${serviceLabel}
    </div>
    <div style="font-size: 13px; color: #666; margin-top: 4px;">
      ${shipment.pol} → ${shipment.pod} | ${shipment.qty} x ${shipment.containerType} | Ready: ${shipment.readyDate}
    </div>
    ${addressBlock}
  </div>
  <table style="width: 100%; border-collapse: collapse;">
    <thead>
      <tr style="background: #fafafa; border-bottom: 1px solid #e0e0e0;">
        <th style="padding: 10px; text-align: left; font-size: 12px; color: #666;">Agent</th>
        <th style="padding: 10px; text-align: left; font-size: 12px; color: #666;">Carrier</th>
        <th style="padding: 10px; text-align: right; font-size: 12px; color: #666;">Price (USD)</th>
        <th style="padding: 10px; text-align: center; font-size: 12px; color: #666;">Transit</th>
        <th style="padding: 10px; text-align: center; font-size: 12px; color: #666;">ETD</th>
        <th style="padding: 10px; text-align: center; font-size: 12px; color: #666;">Free Time</th>
        <th style="padding: 10px; text-align: center; font-size: 12px; color: #666;">Valid Until</th>
      </tr>
    </thead>
    <tbody>`;

    if (shipment.quotes.length === 0) {
      htmlSummary += `
      <tr>
        <td colspan="7" style="padding: 20px; text-align: center; color: #999;">No quotes received</td>
      </tr>`;
    } else {
      for (let i = 0; i < shipment.quotes.length; i++) {
        const q = shipment.quotes[i];
        const isLowest = i === 0;
        const rowStyle = isLowest ? 'background: #e8f5e9;' : '';
        const priceStyle = isLowest ? 'color: #2e7d32; font-weight: bold;' : '';
        const badge = isLowest ? '<span style="background: #4caf50; color: white; padding: 2px 6px; border-radius: 3px; font-size: 10px; margin-right: 5px;">BEST</span>' : '';

        htmlSummary += `
      <tr style="${rowStyle} border-bottom: 1px solid #f0f0f0;">
        <td style="padding: 12px; font-size: 13px;">${badge}${q.agent}</td>
        <td style="padding: 12px; font-size: 13px;">${q.carrier}</td>
        <td style="padding: 12px; font-size: 15px; text-align: right; ${priceStyle}">$${q.price}</td>
        <td style="padding: 12px; font-size: 13px; text-align: center;">${q.transit} days</td>
        <td style="padding: 12px; font-size: 13px; text-align: center;">${q.etd}</td>
        <td style="padding: 12px; font-size: 13px; text-align: center;">${q.freeTime} days</td>
        <td style="padding: 12px; font-size: 13px; text-align: center;">${q.validity}</td>
      </tr>`;
      }
    }

    htmlSummary += `
    </tbody>
  </table>
</div>`;
  }

  // ========================================
  // FIND OVERALL BEST PRICE
  // ========================================

  let bestPrice = Infinity;
  let bestAgent = '';
  let bestCarrier = '';
  let bestShipment = 0;

  for (const shipment of shipmentQuotes) {
    if (shipment.quotes.length > 0) {
      const lowestQuote = shipment.quotes[0];
      if (lowestQuote.price < bestPrice) {
        bestPrice = lowestQuote.price;
        bestAgent = lowestQuote.agent;
        bestCarrier = lowestQuote.carrier;
        bestShipment = shipment.number;
      }
    }
  }

  const quoteCount = validQuotes.length;
  const threshold = 2;

  return [{
    json: {
      quoteCount,
      thresholdMet: quoteCount >= threshold,
      bestPrice: bestPrice === Infinity ? null : bestPrice,
      bestAgent,
      bestCarrier,
      bestShipment,
      rfqRef,
      serviceType,
      hasDoorService,
      summaryText: textSummary.join('\n'),
      summaryHtml: htmlSummary,
      totalResponses: allQuotes.length,
      shipmentQuotes
    }
  }];

} catch (e) {
  return [{
    json: {
      quoteCount: 0,
      thresholdMet: false,
      bestPrice: null,
      error: 'Count failed: ' + e.message,
      errorStack: e.stack
    }
  }];
}

// ============================================================
// SIMPLE METHOD: Check if Customer Replied
// ============================================================
// 
// This assumes you have a Gmail node called "Get Thread After Wait"
// that fetches the thread data before this code node runs
//
// ============================================================

try {
  // Get the quotation data with thread ID
  const quotationData = $('Cost Door').first().json;
  const threadId = quotationData.threadId;
  const customerEmail = quotationData.customerEmail;
  const quoteSentTime = quotationData.calculatedAt;

  // Get the Gmail thread messages
  const threadData = $('Customer Reply').first().json;
  const messages = threadData.messages || [];

  // When was our quotation sent?
  const quoteSentDate = new Date(quoteSentTime);

  // Check if customer replied AFTER we sent the quote
  let hasReplied = false;

  for (const msg of messages) {
    // Get message date and sender
    const msgDate = new Date(parseInt(msg.internalDate));
    const fromHeader = msg.payload?.headers?.find(h => h.name.toLowerCase() === 'from');
    const fromEmail = fromHeader?.value || '';

    // Is this from the customer AND after our quote?
    const isFromCustomer = fromEmail.toLowerCase().includes(customerEmail.toLowerCase());
    const isAfterQuote = msgDate > quoteSentDate;

    if (isFromCustomer && isAfterQuote) {
      hasReplied = true;
      break;
    }
  }

  // Return result
  return [{
    json: {
      ...quotationData,  // Pass through all quotation data
      hasReplied: hasReplied,
      shouldSendFollowUp: !hasReplied,
      checkedAt: new Date().toISOString()
    }
  }];

} catch (err) {
  return [{
    json: {
      error: err.message,
      tip: "Make sure 'Get Thread After Wait' Gmail node runs before this"
    }
  }];
}

// ============================================================
// COST CALCULATION - DOOR SERVICE
// Reads from Aggregate node output: $input.first().json.cost_data
// Contains all rows from DO Charges + Destination Charges + Transportation Charges
//
// DO Charges rows:            have 'carrier' field
// Destination Charges rows:   have 'Charge Type' field
// Transportation Charges rows: have 'Place' field
// ============================================================

const rfq   = $('Get Master Status').first().json;
const quote = $('Get Selected Quote').first().json;

if (!rfq || !quote) {
  return [{ json: { error: 'Missing Required Data', missingRFQ: !rfq, missingQuote: !quote } }];
}

// ============================================================
// SPLIT cost_data ARRAY BACK INTO 3 SHEET GROUPS BY SIGNATURE
// ============================================================

const costData = $input.first().json.cost_data || [];

const allDOCharges     = costData.filter(r => r.carrier !== undefined && r.carrier !== null && r.carrier !== '');
const allDestCharges   = costData.filter(r => r['Charge Type'] !== undefined && r['Charge Type'] !== null && r['Charge Type'] !== '');
const allTranspCharges = costData.filter(r => r.Place !== undefined && r.Place !== null && r.Place !== '');

// ============================================================
// HELPERS
// ============================================================

function parseMultiValue(value) {
  if (!value) return ['N/A'];
  if (typeof value === 'string' && value.includes('\n')) return value.split('\n').map(v => v.trim());
  return [value];
}

// DO Charges sheet: columns 20FT, 40FT, 40HQ
function getDOCol(containerType) {
  const t = (containerType || '').toUpperCase().replace(/[^A-Z0-9]/g, '');
  if (t === '20FT' || t === '20GP') return '20FT';
  if (t === '40FT' || t === '40GP') return '40FT';
  return '40HQ'; // 40HC, 40HQ, 45FT
}

// Destination Charges sheet: columns 20FT, 40FT only (no 40HQ)
function getDestCol(containerType) {
  const t = (containerType || '').toUpperCase().replace(/[^A-Z0-9]/g, '');
  if (t === '20FT' || t === '20GP') return '20FT';
  return '40FT'; // 40FT, 40HC, 40HQ all map here
}

function getDOChargesRow(carrier) {
  const c = (carrier || '').toUpperCase().trim();
  for (const row of allDOCharges) {
    if ((row.carrier || '').toUpperCase().trim() === c) return row;
  }
  return allDOCharges.length > 0 ? allDOCharges[0] : {};
}

// Basis: "Fixed (per shipment)" → once, anything else → × qty
function calcDestCharges(col, qty) {
  let total = 0;
  for (const row of allDestCharges) {
    const amount = parseFloat(row[col]) || 0;
    const basis  = (row['Basis'] || row['basis'] || '').toLowerCase();
    total += basis.includes('fixed') ? amount : amount * qty;
  }
  return total;
}

function getTransportCharge(deliveryAddress) {
  if (!deliveryAddress) return 0;
  const addr = deliveryAddress.toUpperCase();
  for (const row of allTranspCharges) {
    const place = (row.Place || row.place || '').toUpperCase().trim();
    if (place && addr.includes(place)) {
      return parseFloat(row.Price || row.price || 0);
    }
  }
  return 0;
}

// ============================================================
// SERVICE TYPE FLAGS
// ============================================================

const serviceType     = (rfq.service_type || 'port-to-port').toLowerCase().trim();
const hasPickup       = serviceType === 'door-to-port'  || serviceType === 'door-to-door';
const hasDelivery     = serviceType === 'port-to-door'  || serviceType === 'door-to-door';
const deliveryAddress = rfq.delivery_address || null;
const pickupAddress   = rfq.pickup_address   || null;

// ============================================================
// CONSTANTS
// ============================================================

const USD_TO_AED = 3.685;
const MARGIN     = 0.13;

// ============================================================
// PARSE MULTI-SHIPMENT FIELDS
// ============================================================

const containerTypes = parseMultiValue(rfq.container_type);
const quantities     = parseMultiValue(rfq.qty);
const pols           = parseMultiValue(rfq.pol);
const pods           = parseMultiValue(rfq.pod);
const readyDates     = parseMultiValue(rfq.ready_date);
const carriers       = parseMultiValue(quote.carrier);
const prices         = parseMultiValue(quote.price);
const validities     = parseMultiValue(quote.validity);
const transitTimes   = parseMultiValue(quote.transit_time);
const freeTimes      = parseMultiValue(quote.free_time);
const etds           = parseMultiValue(quote.etd);

const shipmentCount = Math.max(containerTypes.length, quantities.length, prices.length);

// ============================================================
// CALCULATE EACH SHIPMENT
// ============================================================

const shipmentCalculations = [];
let grandTotalAED = 0;
let grandTotalUSD = 0;

for (let i = 0; i < shipmentCount; i++) {
  const containerType   = containerTypes[i] || containerTypes[0] || '40HQ';
  const qty             = parseInt(quantities[i] || quantities[0] || 1);
  const carrier         = carriers[i]    || carriers[0]    || 'TBD';
  const oceanFreightUSD = parseFloat(prices[i] || prices[0] || 0);
  const pol             = pols[i]        || pols[0]        || 'N/A';
  const pod             = pods[i]        || pods[0]        || 'N/A';
  const readyDate       = readyDates[i]  || readyDates[0]  || 'TBD';
  const validity        = validities[i]  || validities[0]  || 'N/A';
  const transitTime     = transitTimes[i]|| transitTimes[0]|| 'N/A';
  const freeTime        = freeTimes[i]   || freeTimes[0]   || 'N/A';
  const etd             = etds[i]        || etds[0]        || 'TBD';

  const doCol   = getDOCol(containerType);
  const destCol = getDestCol(containerType);

  // Ocean Freight
  const oceanFreightAED = oceanFreightUSD * USD_TO_AED;

  // DO Charges (carrier-specific: document fixed + per-container)
  const doRow          = getDOChargesRow(carrier);
  const doDocument     = parseFloat(doRow.document || 0);
  const doPerContainer = parseFloat(doRow[doCol]   || 0);
  const doTotal        = doDocument + (doPerContainer * qty);

  // Destination Charges (Terminal Handling, BOE, DPC, Token, etc.)
  const destTotal = calcDestCharges(destCol, qty);

  // Transportation / Delivery Trucking
  const transpPerContainer = hasDelivery ? getTransportCharge(deliveryAddress) : 0;
  const transpTotal        = transpPerContainer * qty;

  // Pickup trucking — no sheet yet, wire in when available
  const pickupTotal = 0;

  // Subtotal + 13% margin
  const subtotalAED   = oceanFreightAED + doTotal + destTotal + transpTotal + pickupTotal;
  const withMarginAED = subtotalAED * (1 + MARGIN);
  const finalPriceAED = Math.ceil(withMarginAED / 10) * 10;
  const pricePerContainerAED = Math.round(finalPriceAED / qty);
  const finalPriceUSD        = Math.round((finalPriceAED / USD_TO_AED) * 100) / 100;
  const pricePerContainerUSD = Math.round((finalPriceUSD / qty) * 100) / 100;

  shipmentCalculations.push({
    shipmentNumber: i + 1,
    serviceType,
    pol, pod, containerType, qty, readyDate,
    carrier, validity, transitTime, freeTime, etd,
    pickupAddress:   hasPickup   ? pickupAddress   : null,
    deliveryAddress: hasDelivery ? deliveryAddress : null,
    // Pricing breakdown
    oceanFreightUSD,
    oceanFreightAED:     Math.round(oceanFreightAED * 100) / 100,
    doDocument,
    doPerContainer,
    doTotal:             Math.round(doTotal * 100) / 100,
    destTotal:           Math.round(destTotal * 100) / 100,
    transpPerContainer,
    transpTotal:         Math.round(transpTotal * 100) / 100,
    subtotalAED:         Math.round(subtotalAED * 100) / 100,
    marginAmount:        Math.round((withMarginAED - subtotalAED) * 100) / 100,
    finalPriceAED,
    pricePerContainerAED,
    finalPriceUSD,
    pricePerContainerUSD
  });

  grandTotalAED += finalPriceAED;
  grandTotalUSD += finalPriceUSD;
}

