// ============================================================
// COST CALCULATION - PORT TO PORT
// Simple: agent ocean freight + 13% margin only
// ============================================================

const getData = (nodeName) => {
  try { return $(nodeName).first().json; } catch (e) { return null; }
};

const rfq = getData('Get Master Status');
const quote = getData('Get Selected Quote');

if (!rfq || !quote) {
  return [{ json: { error: 'Missing Required Data', missingRFQ: !rfq, missingQuote: !quote } }];
}

function parseMultiValue(value) {
  if (!value) return ['N/A'];
  if (typeof value === 'string' && value.includes('\n')) return value.split('\n').map(v => v.trim());
  return [value];
}

const USD_TO_AED = 3.685;
const MARGIN = 0.13;

const containerTypes = parseMultiValue(rfq.container_type);
const quantities     = parseMultiValue(rfq.qty);
const pols           = parseMultiValue(rfq.pol);
const pods           = parseMultiValue(rfq.pod);
const readyDates     = parseMultiValue(rfq.ready_date);
const carriers       = parseMultiValue(quote.carrier);
const prices         = parseMultiValue(quote.price);
const validities     = parseMultiValue(quote.validity);
const transitTimes   = parseMultiValue(quote.transit_time);
const freeTimes      = parseMultiValue(quote.free_time);
const etds           = parseMultiValue(quote.etd);

const shipmentCount = Math.max(containerTypes.length, quantities.length, prices.length);

const shipmentCalculations = [];
let grandTotalAED = 0;
let grandTotalUSD = 0;

for (let i = 0; i < shipmentCount; i++) {
  const containerType       = containerTypes[i] || containerTypes[0] || '40HQ';
  const qty                 = parseInt(quantities[i] || quantities[0] || 1);
  const carrier             = carriers[i] || carriers[0] || 'TBD';
  const oceanFreightUSD     = parseFloat(prices[i] || prices[0] || 0);
  const pol                 = pols[i] || pols[0] || 'N/A';
  const pod                 = pods[i] || pods[0] || 'N/A';
  const readyDate           = readyDates[i] || readyDates[0] || 'TBD';
  const validity            = validities[i] || validities[0] || 'N/A';
  const transitTime         = transitTimes[i] || transitTimes[0] || 'N/A';
  const freeTime            = freeTimes[i] || freeTimes[0] || 'N/A';
  const etd                 = etds[i] || etds[0] || 'TBD';

  const oceanFreightAED     = oceanFreightUSD * USD_TO_AED;
  const withMarginAED       = oceanFreightAED * (1 + MARGIN);
  const finalPriceAED       = Math.ceil(withMarginAED / 10) * 10;
  const pricePerContainerAED = Math.round(finalPriceAED / qty);
  const finalPriceUSD       = Math.round((finalPriceAED / USD_TO_AED) * 100) / 100;
  const pricePerContainerUSD = Math.round((finalPriceUSD / qty) * 100) / 100;

  shipmentCalculations.push({
    shipmentNumber: i + 1,
    serviceType: 'port-to-port',
    pol, pod, containerType, qty, readyDate,
    carrier, validity, transitTime, freeTime, etd,
    // Pricing breakdown
    oceanFreightUSD,
    oceanFreightAED:          Math.round(oceanFreightAED * 100) / 100,
    destCharges:              0,
    doorChargesAED:           0,
    subtotalAED:              Math.round(oceanFreightAED * 100) / 100,
    marginAmount:             Math.round((withMarginAED - oceanFreightAED) * 100) / 100,
    finalPriceAED,
    pricePerContainerAED,
    finalPriceUSD,
    pricePerContainerUSD
  });

  grandTotalAED += finalPriceAED;
  grandTotalUSD += finalPriceUSD;
}

// Build customer summary text
const customerSummaryText = shipmentCalculations.map((c, idx) => {
  const lines = [];
  if (shipmentCount > 1) lines.push(`SHIPMENT ${c.shipmentNumber} of ${shipmentCount}\n`);
  lines.push(`Route: ${c.pol} to ${c.pod}`);
  lines.push(`Container(s): ${c.qty} x ${c.containerType}`);
  lines.push(`Ready Date: ${c.readyDate}`);
  lines.push('');
  lines.push(`Carrier: ${c.carrier}`);
  lines.push(`Transit Time: ${c.transitTime} days`);
  lines.push(`Free Time: ${c.freeTime} days at destination`);
  lines.push(`ETD: ${c.etd}`);
  lines.push(`Total Price (AED): ${c.finalPriceAED.toLocaleString()}`);
  lines.push(`Total Price (USD): ${c.finalPriceUSD.toLocaleString()}`);
  if (shipmentCount > 1) lines.push('\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
  return lines.join('\n');
}).join('\n');

const first = shipmentCalculations[0] || {};

